code = """import json
import re

# Process the clinical data to extract barcodes and histological types
file_path = locals()['var_functions.query_db:30']
with open(file_path, 'r') as f:
    lgg_clinical = json.load(f)

# Extract patient data
lgg_patient_data = []
for record in lgg_clinical:
    desc = record['Patient_description']
    hist_type = record['histological_type']
    
    # Extract TCGA barcode
    match = re.search(r'(TCGA-\w+-\w+)', desc)
    if match and hist_type and not hist_type.startswith('['):
        barcode = match.group(1)
        lgg_patient_data.append({
            'barcode': barcode,
            'histological_type': hist_type
        })

# Group by histological type
histology_groups = {}
for patient in lgg_patient_data:
    hist_type = patient['histological_type']
    if hist_type not in histology_groups:
        histology_groups[hist_type] = []
    histology_groups[hist_type].append(patient['barcode'])

print('__RESULT__:')
print(json.dumps({
    'total_patients': len(lgg_patient_data),
    'histology_types': list(histology_groups.keys()),
    'histology_counts': {k: len(v) for k, v in histology_groups.items()},
    'sample_data': lgg_patient_data[:5]
}))"""

